```tsx
// 인사 컴포넌트
import { useState } from "react";

interface 인사Props {
  이름: string;
}

export function 인사카드({ 이름 }: 인사Props) {
  const [인사횟수, 인사횟수설정] = useState(0);

  const 인사하기 = () => {
    인사횟수설정(이전 => 이전 + 1);
