## 핵심: Server-Sent Events(SSE) + 차트

```tsx
// app/dashboard/page.tsx
"use client";
import { useState, useEffect } from "react";

interface 메트릭 {
  cpu: number;
  memory: number;
  requests: number;
  errors: number;
  responseTime: number;
  timestamp: string;
}

export default function 대시보드() {
  const [메트릭들, 메트릭설정] = useState<메트릭[]>([]);
  const [현재, 현재설정] = useState<메트릭 | null>(null);

  useEffect(() => {
    // SSE 연결 (실시간 데이터 수신)
    const eventSource = new EventSource("/api/metrics/stream");

    eventSource.onmessage = (event) => {
      const 데이터: 메트릭 = JSON.parse(event.data);
      현재설정(데이터);
      메트릭설정(이전 => [...이전.slice(-59), 데이터]); // 최근 60개
    };

    return () => eventSource.close();
  }, []);

  if (!현재) return <div className="p-8 text-center">연결 중...</div>;

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold">실시간 모니터링</h1>

      {/* 핵심 지표 카드 */}
      <div className="grid grid-cols-4 gap-4">
        <MetricCard title="CPU" value={`${현재.cpu}%`}
          color={현재.cpu > 80 ? "red" : 현재.cpu > 50 ? "yellow" : "green"} />
        <MetricCard title="메모리" value={`${현재.memory}%`}
          color={현재.memory > 80 ? "red" : "green"} />
        <MetricCard title="요청/초" value={현재.requests.toString()} color="blue" />
        <MetricCard title="응답시간" value={`${현재.responseTime}ms`}
          color={현재.responseTime > 1000 ? "red" : "green"} />
      </div>

      {/* 실시간 차트 (최근 60초) */}
      <div className="bg-white rounded-xl border p-4">
        <h3 className="font-semibold mb-4">CPU / 메모리 추이 (60초)</h3>
        <div className="h-64 flex items-end gap-1">
          {메트릭들.map((m, i) => (
            <div key={i} className="flex-1 flex flex-col gap-1">
              <div
                className="bg-blue-500 rounded-t"
                style={{ height: `${m.cpu * 2}px` }}
                title={`CPU ${m.cpu}%`}
              />
              <div
                className="bg-green-500 rounded-t"
                style={{ height: `${m.memory * 2}px` }}
                title={`MEM ${m.memory}%`}
              />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function MetricCard({ title, value, color }: { title: string; value: string; color: string }) {
  const colors = {
    red: "border-red-500 text-red-600",
    yellow: "border-yellow-500 text-yellow-600",
    green: "border-green-500 text-green-600",
    blue: "border-blue-500 text-blue-600",
  };
  return (
    <div className={`rounded-xl border-2 p-4 ${colors[color]}`}>
      <div className="text-sm opacity-70">{title}</div>
      <div className="text-3xl font-bold">{value}</div>
    </div>
  );
}
```

## SSE 엔드포인트

```typescript
// app/api/metrics/stream/route.ts
export async function GET() {
  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    start(controller) {
      const interval = setInterval(() => {
        const 메트릭 = {
          cpu: Math.round(Math.random() * 100),
          memory: Math.round(50 + Math.random() * 40),
          requests: Math.round(Math.random() * 500),
          errors: Math.round(Math.random() * 5),
          responseTime: Math.round(50 + Math.random() * 200),
          timestamp: new Date().toISOString(),
        };
        controller.enqueue(encoder.encode(`data: ${JSON.stringify(메트릭)}\n\n`));
      }, 1000); // 1초마다

      // 정리
      setTimeout(() => {
        clearInterval(interval);
        controller.close();
      }, 3600000); // 1시간 후 종료
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}
```

SSE는 WebSocket보다 간단하고, 서버→클라이언트 단방향 실시간 데이터에 적합합니다.

이 에러는 `undefined`인 객체의 속성에 접근할 때 발생합니다.

```javascript
// ❌ 에러 발생
const user = undefined;
console.log(user.name); // TypeError!

// ✅ 해결 방법들

// 1. 옵셔널 체이닝 (?.)
console.log(user?.name); // undefined (에러 안 남)

// 2. 기본값 (Nullish coalescing)
console.log(user?.name ?? "이름 없음");

// 3. 조건 체크
if (user && user.name) {
    console.log(user.name);
}

// 4. API 응답에서 자주 발생
const response = await fetch("/api/user");
const data = await response.json();
// data.user가 null일 수 있음
const userName = data?.user?.name ?? "게스트";
```

**흔한 원인:**
- API 응답이 예상과 다른 구조
- 배열이 비어있는데 `arr[0].name` 접근
- 비동기 로딩 중 데이터가 아직 없을 때
- `useState`의 초기값이 `null`

CORS 에러는 브라우저가 다른 도메인의 API를 차단할 때 발생합니다.

```
에러: Access to fetch at 'http://api.example.com' from origin
'http://localhost:3000' has been blocked by CORS policy
```

**해결 방법:**

```javascript
// ── 1. 서버에서 CORS 허용 (백엔드) ──

// Express
const cors = require("cors");
app.use(cors({
    origin: ["http://localhost:3000", "https://내도메인.com"],
    methods: ["GET", "POST", "PUT", "DELETE"],
    credentials: true,  // 쿠키 포함 시
}));

// FastAPI
from fastapi.middleware.cors import CORSMiddleware
app.add_middleware(
    CORSMiddleware,
    allow_origins=["http://localhost:3000"],
    allow_methods=["*"],
    allow_headers=["*"],
    allow_credentials=True,
)

// Next.js API Route (자동으로 같은 도메인)
// → CORS 문제 없음! 프록시로 해결

// ── 2. Next.js 프록시 (프론트) ──

// next.config.ts
const nextConfig = {
    async rewrites() {
        return [
            {
                source: "/api/external/:path*",
                destination: "http://api.example.com/:path*",
            },
        ];
    },
};

// 프론트에서
fetch("/api/external/users"); // 같은 도메인 → CORS 없음
```

**핵심: 백엔드에서 `Access-Control-Allow-Origin` 헤더를 추가하거나, 같은 도메인 프록시를 사용하세요.**

React 성능 최적화 핵심 기법들입니다.

```tsx
// ── 1. React.memo (불필요한 리렌더링 방지) ──

// ❌ 부모가 렌더링되면 매번 같이 렌더링
function 자식({ 이름 }: { 이름: string }) {
    console.log("렌더링됨!");
    return <div>{이름}</div>;
}

// ✅ props가 변경될 때만 렌더링
const 자식 = React.memo(function 자식({ 이름 }: { 이름: string }) {
    console.log("렌더링됨!");
    return <div>{이름}</div>;
});

// ── 2. useMemo (비싼 계산 캐싱) ──

function 컴포넌트({ 데이터 }: { 데이터: number[] }) {
    // ❌ 매 렌더링마다 재계산
    const 합계 = 데이터.reduce((a, b) => a + b, 0);

    // ✅ 데이터가 변할 때만 재계산
    const 합계 = useMemo(
        () => 데이터.reduce((a, b) => a + b, 0),
        [데이터]
    );

    return <div>합계: {합계}</div>;
}

// ── 3. useCallback (함수 참조 고정) ──

function 부모() {
    const [카운트, 카운트설정] = useState(0);

    // ❌ 매 렌더링마다 새 함수 생성
    const 클릭 = () => console.log("클릭");

    // ✅ 의존성 변할 때만 새 함수
    const 클릭 = useCallback(() => {
        console.log("클릭", 카운트);
    }, [카운트]);

    return <자식 onClick={클릭} />;
}

// ── 4. 가상화 (대량 리스트) ──

import { useVirtualizer } from "@tanstack/react-virtual";

function 대량리스트({ 아이템들 }: { 아이템들: string[] }) {
    const parentRef = useRef<HTMLDivElement>(null);

    const virtualizer = useVirtualizer({
        count: 아이템들.length,  // 10만개라도 OK
        getScrollElement: () => parentRef.current,
        estimateSize: () => 50,  // 아이템 높이
    });

    return (
        <div ref={parentRef} style={{ height: "400px", overflow: "auto" }}>
            <div style={{ height: virtualizer.getTotalSize() }}>
                {virtualizer.getVirtualItems().map(item => (
                    <div key={item.key} style={{
                        position: "absolute",
                        top: item.start,
                        height: item.size,
                    }}>
                        {아이템들[item.index]}
                    </div>
                ))}
            </div>
        </div>
    );
}
// 10만개 아이템도 DOM에는 ~10개만 렌더링!

// ── 5. 코드 분할 (lazy loading) ──

const 무거운컴포넌트 = lazy(() => import("./HeavyComponent"));

function 앱() {
    return (
        <Suspense fallback={<div>로딩 중...</div>}>
            <무거운컴포넌트 />
        </Suspense>
    );
}

// ── 6. 이미지 최적화 (Next.js) ──

import Image from "next/image";

// ❌
<img src="/big-photo.jpg" />

// ✅ 자동 최적화 + lazy loading
<Image src="/big-photo.jpg" width={800} height={600} alt="사진" />
```

