function UserName() {
  // user가 바뀔 때만 리렌더
  const name = useAuthStore((state) => state.user?.name);
  return <span>{name}</span>;
}

// ═══ 2. React Context (간단한 전역 상태) ═══
// 테마, 언어 등 자주 바뀌지 않는 것에 적합
import { createContext, useContext, useState, ReactNode } from "react";

interface ThemeContextType {
  theme: "light" | "dark";
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState<"light" | "dark">("light");

  const toggleTheme = () => {
    setTheme((prev) => (prev === "light" ? "dark" : "light"));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (!context) throw new Error("ThemeProvider 안에서 사용하세요");
  return context;
}

// ═══ 3. TanStack Query (서버 상태) ═══
// API 데이터 캐싱, 로딩 상태, 에러 처리 자동화
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";

function UserList() {
  const { data, isLoading, error } = useQuery({
    queryKey: ["users"],
    queryFn: () => fetch("/api/users").then((r) => r.json()),
    staleTime: 5 * 60 * 1000,    // 5분간 캐시 유지
    refetchOnWindowFocus: true,   // 탭 복귀 시 리페치
  });

  if (isLoading) return <Skeleton />;
  if (error) return <Error message={error.message} />;
  return <ul>{data.map((u) => <li key={u.id}>{u.name}</li>)}</ul>;
}

function CreateUserForm() {
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: (data: CreateUserInput) =>
      fetch("/api/users", { method: "POST", body: JSON.stringify(data) }),
    onSuccess: () => {
      // 사용자 목록 캐시 무효화 → 자동 리페치
      queryClient.invalidateQueries({ queryKey: ["users"] });
    },
  });

  return (
    <form onSubmit={(e) => {
      e.preventDefault();
      mutation.mutate({ name: "홍길동", email: "hong@test.com" });
    }}>
      <button disabled={mutation.isPending}>
        {mutation.isPending ? "추가 중..." : "사용자 추가"}
      </button>
    </form>
  );
}
```

**선택 가이드:**
| 상황 | 추천 |
|------|------|
| 서버 데이터 (API) | TanStack Query |
| 클라이언트 전역 상태 | Zustand |
| 테마/언어 (적은 업데이트) | React Context |
| 폼 상태 | React Hook Form |
| 복잡한 비동기 로직 | Zustand + TanStack Query |

실무에서 자주 쓰는 커스텀 훅 모음입니다.

```tsx
import { useState, useEffect, useRef, useCallback } from "react";

// 1. useDebounce - 입력 디바운스
function useDebounce<T>(value: T, delay: number = 300): T {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
}

// 사용: 검색 입력에서 API 호출 최소화
function SearchInput() {
  const [query, setQuery] = useState("");
  const debouncedQuery = useDebounce(query, 300);

  useEffect(() => {
    if (debouncedQuery) {
      fetchSearchResults(debouncedQuery);
    }
  }, [debouncedQuery]);
}

// 2. useLocalStorage - 로컬 스토리지 동기화
function useLocalStorage<T>(key: string, initialValue: T) {
  const [storedValue, setStoredValue] = useState<T>(() => {
    if (typeof window === "undefined") return initialValue;
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = useCallback((value: T | ((val: T) => T)) => {
    const valueToStore = value instanceof Function ? value(storedValue) : value;
    setStoredValue(valueToStore);
    window.localStorage.setItem(key, JSON.stringify(valueToStore));
  }, [key, storedValue]);

  return [storedValue, setValue] as const;
}

// 3. useMediaQuery - 반응형 감지
function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(false);

  useEffect(() => {
    const media = window.matchMedia(query);
    setMatches(media.matches);
    const listener = (e: MediaQueryListEvent) => setMatches(e.matches);
    media.addEventListener("change", listener);
    return () => media.removeEventListener("change", listener);
  }, [query]);

  return matches;
}

// 사용
function Layout() {
  const isMobile = useMediaQuery("(max-width: 768px)");
  return isMobile ? <MobileLayout /> : <DesktopLayout />;
}

// 4. useIntersectionObserver - 무한 스크롤 / Lazy Load
function useIntersectionObserver(
  callback: () => void,
  options?: IntersectionObserverInit
) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) callback();
    }, options);

    observer.observe(element);
    return () => observer.disconnect();
  }, [callback, options]);

  return ref;
}

// 무한 스크롤 사용
function PostList() {
  const { data, fetchNextPage, hasNextPage } = useInfiniteQuery({...});
  const loadMoreRef = useIntersectionObserver(() => {
    if (hasNextPage) fetchNextPage();
  });

  return (
    <div>
      {data?.pages.map((page) =>
        page.posts.map((post) => <PostCard key={post.id} post={post} />)
      )}
      <div ref={loadMoreRef} /> {/* 이 요소가 보이면 다음 페이지 로드 */}
    </div>
  );
}

// 5. useCopyToClipboard - 클립보드 복사
function useCopyToClipboard() {
  const [copied, setCopied] = useState(false);

  const copy = useCallback(async (text: string) => {
    await navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }, []);

  return { copy, copied };
}

// 6. useClickOutside - 외부 클릭 감지
function useClickOutside(
  ref: React.RefObject<HTMLElement>,
  handler: () => void
) {
  useEffect(() => {
    const listener = (e: MouseEvent) => {
      if (!ref.current || ref.current.contains(e.target as Node)) return;
      handler();
    };
    document.addEventListener("mousedown", listener);
    return () => document.removeEventListener("mousedown", listener);
  }, [ref, handler]);
}

// 드롭다운 닫기
function Dropdown() {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  useClickOutside(ref, () => setOpen(false));

  return (
    <div ref={ref}>
      <button onClick={() => setOpen(!open)}>메뉴</button>
      {open && <DropdownMenu />}
    </div>
  );
}
```

커스텀 훅 규칙:
- `use`로 시작 (React 규칙)
- 하나의 관심사만 담당
- 반환값은 `[value, setter]` 또는 객체 `{ data, loading }`
- 내부에서 다른 훅 사용 가능

