React Hook Form + Zod로 타입 안전한 폼을 만듭니다.

```tsx
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";

// 1. Zod 스키마 정의
const signupSchema = z.object({
  name: z.string()
    .min(2, "이름은 2자 이상 입력하세요")
    .max(50, "이름은 50자 이하로 입력하세요"),
  email: z.string()
    .email("올바른 이메일을 입력하세요"),
  password: z.string()
    .min(8, "비밀번호는 8자 이상이어야 합니다")
    .regex(/[A-Z]/, "대문자를 포함해야 합니다")
    .regex(/[0-9]/, "숫자를 포함해야 합니다")
    .regex(/[^A-Za-z0-9]/, "특수문자를 포함해야 합니다"),
  confirmPassword: z.string(),
  agreeTerms: z.boolean().refine((val) => val, {
    message: "이용약관에 동의해야 합니다",
  }),
}).refine((data) => data.password === data.confirmPassword, {
  message: "비밀번호가 일치하지 않습니다",
  path: ["confirmPassword"],
});

// 타입 자동 추론
type SignupForm = z.infer<typeof signupSchema>;

// 2. 폼 컴포넌트
export function SignupForm() {
  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
    watch,
    reset,
  } = useForm<SignupForm>({
    resolver: zodResolver(signupSchema),
    defaultValues: {
      name: "",
      email: "",
      password: "",
      confirmPassword: "",
      agreeTerms: false,
    },
  });

  const onSubmit = async (data: SignupForm) => {
    try {
      const response = await fetch("/api/auth/signup", {
        method: "POST",
        body: JSON.stringify(data),
      });
      if (!response.ok) throw new Error("가입 실패");
      reset();
      toast.success("가입 완료!");
    } catch (error) {
      toast.error("가입에 실패했습니다");
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
      {/* 이름 */}
      <div>
        <label htmlFor="name" className="block text-sm font-medium">
          이름
        </label>
        <input
          id="name"
          {...register("name")}
          className={cn(
            "mt-1 block w-full rounded-lg border px-3 py-2",
            errors.name
              ? "border-red-500 focus:ring-red-500"
              : "border-gray-300 focus:ring-blue-500"
          )}
        />
        {errors.name && (
          <p className="mt-1 text-sm text-red-500">{errors.name.message}</p>
        )}
      </div>

      {/* 이메일 */}
      <div>
        <label htmlFor="email">이메일</label>
        <input id="email" type="email" {...register("email")} />
        {errors.email && <p className="text-red-500">{errors.email.message}</p>}
      </div>

      {/* 비밀번호 */}
      <div>
        <label htmlFor="password">비밀번호</label>
        <input id="password" type="password" {...register("password")} />
        {errors.password && <p className="text-red-500">{errors.password.message}</p>}
        {/* 비밀번호 강도 표시 */}
        <PasswordStrength password={watch("password")} />
      </div>

      {/* 비밀번호 확인 */}
      <div>
        <label htmlFor="confirmPassword">비밀번호 확인</label>
        <input id="confirmPassword" type="password" {...register("confirmPassword")} />
        {errors.confirmPassword && (
          <p className="text-red-500">{errors.confirmPassword.message}</p>
        )}
      </div>

      {/* 이용약관 동의 */}
      <div className="flex items-center gap-2">
        <input id="terms" type="checkbox" {...register("agreeTerms")} />
        <label htmlFor="terms">이용약관에 동의합니다</label>
        {errors.agreeTerms && (
          <p className="text-red-500">{errors.agreeTerms.message}</p>
        )}
      </div>

      <button
        type="submit"
        disabled={isSubmitting}
        className="w-full rounded-lg bg-blue-600 py-2 text-white"
      >
        {isSubmitting ? "가입 중..." : "회원가입"}
      </button>
    </form>
  );
}
```

핵심:
- Zod로 스키마 정의 → 타입 자동 추론 (`z.infer`)
- `zodResolver`로 RHF와 연결
- `register`로 입력 필드 등록 (ref + onChange 자동)
- `errors` 객체로 에러 메시지 표시
- `isSubmitting`으로 중복 제출 방지

Next.js App Router의 API 라우트 패턴입니다.

```typescript
// app/api/users/route.ts
import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";
import { z } from "zod";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";

// GET /api/users?page=1&limit=20&search=홍
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get("page") || "1");
    const limit = Math.min(parseInt(searchParams.get("limit") || "20"), 100);
    const search = searchParams.get("search") || "";

    const where = search
      ? {
          OR: [
            { name: { contains: search } },
            { email: { contains: search } },
          ],
        }
      : {};

    const [users, total] = await Promise.all([
      db.user.findMany({
        where,
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { createdAt: "desc" },
        select: {
          id: true,
          name: true,
          email: true,
          createdAt: true,
          _count: { select: { posts: true } },
        },
      }),
      db.user.count({ where }),
    ]);

    return NextResponse.json({
      data: users,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    console.error("사용자 조회 실패:", error);
    return NextResponse.json(
      { error: "서버 오류가 발생했습니다" },
      { status: 500 }
    );
  }
}

// POST /api/users
const createUserSchema = z.object({
  name: z.string().min(2).max(50),
  email: z.string().email(),
});

export async function POST(request: NextRequest) {
  // 인증 확인
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: "로그인 필요" }, { status: 401 });
  }

  try {
    const body = await request.json();
    const validated = createUserSchema.parse(body);

    // 중복 확인
    const existing = await db.user.findUnique({
      where: { email: validated.email },
    });
    if (existing) {
      return NextResponse.json(
        { error: "이미 존재하는 이메일입니다" },
        { status: 409 }
      );
    }

    const user = await db.user.create({ data: validated });

    return NextResponse.json(user, { status: 201 });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json(
        { error: "입력값 오류", details: error.errors },
        { status: 422 }
      );
    }
    return NextResponse.json(
      { error: "서버 오류" },
      { status: 500 }
    );
  }
}

// app/api/users/[id]/route.ts
// GET/PATCH/DELETE /api/users/:id
export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;
  const body = await request.json();

  const user = await db.user.update({
    where: { id },
    data: body,
  });

  return NextResponse.json(user);
}
```

핵심:
- Zod로 입력 검증
- `getServerSession`으로 인증 확인
- 페이지네이션은 `page`/`limit` 쿼리 파라미터
- 에러 응답은 일관된 `{ error: string }` 형식
- dynamic route는 `[id]/route.ts`

