// 이벤트 발행
bus.emit("user:created", newUser);

// ═══ 2. 도메인 이벤트 패턴 ═══
interface DomainEvent {
  type: string;
  timestamp: Date;
  aggregateId: string;
  payload: Record<string, unknown>;
}

class Order {
  private events: DomainEvent[] = [];

  place(items: OrderItem[]) {
    // 비즈니스 로직
    this.status = "placed";
    this.items = items;

    // 도메인 이벤트 기록
    this.events.push({
      type: "OrderPlaced",
      timestamp: new Date(),
      aggregateId: this.id,
      payload: { items, total: this.total },
    });
  }

  cancel(reason: string) {
    if (this.status === "shipped") {
      throw new Error("배송 시작 후 취소 불가");
    }
    this.status = "cancelled";
    this.events.push({
      type: "OrderCancelled",
      timestamp: new Date(),
      aggregateId: this.id,
      payload: { reason },
    });
  }

  pullEvents(): DomainEvent[] {
    const events = [...this.events];
    this.events = [];
    return events;
  }
}

// 리포지토리에서 이벤트 발행
async function saveOrder(order: Order) {
  await db.save(order);
  const events = order.pullEvents();
  for (const event of events) {
    await eventBus.publish(event);  // 비동기 처리
  }
}

// ═══ 3. CQRS (Command Query Responsibility Segregation) ═══
// 쓰기(Command)와 읽기(Query) 분리

// 커맨드 (쓰기)
interface CreateOrderCommand {
  type: "CreateOrder";
  customerId: string;
  items: { productId: string; quantity: number }[];
}

class CommandHandler {
  async handle(command: CreateOrderCommand) {
    const order = new Order(command.customerId, command.items);
    await this.orderRepo.save(order);
    // 이벤트 발행 → Read Model 업데이트
  }
}

// 쿼리 (읽기) - 별도 최적화된 모델
interface OrderSummary {
  id: string;
  customerName: string;  // 비정규화
  itemCount: number;
  total: number;
  status: string;
}

class QueryHandler {
  async getOrderSummaries(customerId: string): Promise<OrderSummary[]> {
    // 읽기 전용 DB/캐시에서 조회 (빠름)
    return this.readDb.query(
      "SELECT * FROM order_summaries WHERE customer_id = ?",
      [customerId]
    );
  }
}

// ═══ 4. 이벤트 소싱 (Event Sourcing) ═══
// 상태 대신 이벤트의 시퀀스를 저장

class EventStore {
  async append(aggregateId: string, events: DomainEvent[]) {
    await db.insert("events", events.map((e) => ({
      aggregate_id: aggregateId,
      type: e.type,
      payload: JSON.stringify(e.payload),
      timestamp: e.timestamp,
    })));
  }

  async getEvents(aggregateId: string): Promise<DomainEvent[]> {
    return db.query(
      "SELECT * FROM events WHERE aggregate_id = ? ORDER BY timestamp",
      [aggregateId]
    );
  }
}

// 이벤트에서 현재 상태 재구성
function rebuildOrder(events: DomainEvent[]): Order {
  const order = new Order();
  for (const event of events) {
    switch (event.type) {
      case "OrderPlaced":
        order.status = "placed";
        order.items = event.payload.items;
        break;
      case "OrderPaid":
        order.status = "paid";
        break;
      case "OrderCancelled":
        order.status = "cancelled";
        break;
    }
  }
  return order;
}
