      email: () => new EmailNotification(),
      sms: () => new SMSNotification(),
      slack: () => new SlackNotification(),
      push: () => new PushNotification(),
    };
    const factory = map[type];
    if (!factory) throw new Error(`지원하지 않는 알림 유형: ${type}`);
    return factory();
  }
}

